import React from 'react';
import '../App.css';
import {
  Container, Row, Col,
  Button
} from 'react-bootstrap';

import JobTable from './JobTable';
import { DataContext } from '../data-context';
import { Doughnut } from 'react-chartjs-2';
import { MachineRepairForm } from '../forms/RepairForm';
// https://github.com/jerairrest/react-chartjs-2
// https://www.chartjs.org/docs/latest/charts/doughnut.html

export default class Dashboard extends React.Component {

  static contextType = DataContext;

  constructor(...args) {
    super(...args);
    console.log(this.context);
    this.state = {
      ...this.context,
      showMachineRepairForm: false,
      // showMachineRepairForm: true,
    };
  }

  setShowMachineRepairForm(show) {
    this.setState({
      showMachineRepairForm: show
    });
  }


  handleGeneralRepairClick = (e) => {
    // TODO
  }

  render() {
    // let data = this.context.data;
    let data = this.context.data;

    const chartData = {
      labels: ['Backlog', 'WIP', 'Done'],
      datasets: [{
        data: [300, 50, 100],
        backgroundColor: ['#FF4242', '#4242FF', '#42FF42'],
        hoverBackgroundColor: ['#FF0000', '#0000FF', '#00FF00'],
        borderWidth: [1, 1, 1]
      }]
    };

    const chartOptions = {
      legend: {
        display: false
      }
    };

    const data0 = [];
    const data1 = [];
    const data2 = [];
    if (typeof (data) === 'array')
      console.log("data", data)

    data.jobs.forEach((v, i) => {
      console.log('v.status', v.status)
      if (v.status == 0) {
        data0.push(v);
      } else
        if (v.status == 1) {
          data1.push(v);
        } else
          if (v.status == 2) {
            data2.push(v);
          }
    });


    return (
      <>
        <Container fluid>
          <Row className="db-top">
            <Col lg={3} style={{ verticalAlign: 'text-top' }}>
              <Row style={{ height: 240 }}>
                <Doughnut data={chartData} options={chartOptions} />
              </Row>
              <Row style={{ alignContent: 'center' }}>
                <Button size="lg" variant='danger' block onClick={() => this.setShowMachineRepairForm(true)}>Machine Repair</Button>
                <Button size="lg" variant='danger' block onClick={this.handleGeneralRepairClick}>General Repair</Button>
              </Row>
            </Col>
            <Col lg={3}>
              <JobTable
                backlog
                title="Backlog"
                data={data0}
              />
            </Col>
            <Col lg={3}>
              <JobTable
                wip
                title="WIP"
                data={data1}
              />
            </Col>
            <Col lg={3}>
              <JobTable
                done
                title="Done"
                data={data2}
              />
            </Col>
          </Row>

        </Container>

        <MachineRepairForm
          show={this.state.showMachineRepairForm}
          handleClose={() => this.setShowMachineRepairForm(false)}
        />
      </>
    );
  }
}
