import React from 'react';
import '../App.css';
import {
  Container, Row, Col,
  Button
} from 'react-bootstrap';

import { DataContext } from '../data-context.js';

export default class JobTable extends React.Component {

  static contextType = DataContext;
  color = '#ffffff';

  constructor(...args) {
    super(...args);
    // console.log(this.context);
    this.state = {
      ...this.context
    };

    if (this.props.backlog) this.color = '#ffaaaa';
    if (this.props.wip) this.color = '#aaaaff';
    if (this.props.done) this.color = '#aaffaa';
  }

  render() {
    let jobList = [];
    let data = this.props.data;
    // let data = this.context.data;
    // console.log("data",typeof(data),data);

    // data.map((v, i) => {
    jobList = data.map((v, i) => {
      console.log('v',v.startTime)
      return (
        <Row key={i} style={{ color: this.color }}>
          <Col md={2}>
            {v.startTime}
          </Col>
          <Col>
            {v.line}<br />
            {v.machine}<br />
            {v.cause}
          </Col>
        </Row>
      );
    });


    return (
      <Container fluid>
        {this.props.title && <div style={{ textAlign: 'center', fontWeight: 'bold' }}>{this.props.title}</div>}
        <Row className="db-header">
          <Col md={2}>
            Status
            </Col>
          <Col>
            Line/Machine/Cause
            </Col>
        </Row>
        {jobList}
      </Container>

    );
  }
}
