      ...this.context,
      isSubmitting: false,
      // Data
      requestTime: new Date(),
      requester: '',
      line: 'A',
      machineName: '',
      machineCode: '',
      cause: '',
      remark: '',

      wtrepair: false,
      wtmodify: false,
      wtcheck: false,
      wtinstallation: false,
